//! Differential-test corpus generator for the x86 backend.
//!
//! This binary is NOT part of the asmkit repository. It is copied into the
//! extracted *baseline* tree (target/difftest-baseline/src/bin/) by
//! meta/difftest/materialize.sh and built against the pre-rewrite x86 encoder.
//!
//! It drives the baseline's dynamic instruction API (`Instruction::from_mnem`
//! + `emit`) over operand grids derived from `corpus_recipes.rs` (generated by
//! meta/difftest/extract_recipes.py from the baseline's _DYN.rs), and writes a
//! binary corpus of (mnemonic, operands, options, expected bytes) records.
//! See meta/difftest/FORMAT.md for the record format.

use std::collections::{BTreeMap, HashSet};
use std::io::Write;
use std::panic::AssertUnwindSafe;

use asmkit::core::buffer::CodeBuffer;
use asmkit::core::operand::{Imm, Label, Operand, OperandCast, OperandSignature, imm};
use asmkit::x86::assembler::Assembler;
use asmkit::x86::features::dyn_emit::Instruction;
use asmkit::x86::opcodes;
use asmkit::x86::operands::{Broadcast, Mem, Reg};

include!("corpus_recipes.rs");

// ============================================================================
// RegType discriminants (mirror src/core/operand.rs TryFrom<u32>).
// ============================================================================
const RT_NONE: u8 = 0;
const RT_PC: u8 = 3;
const RT_GP8LO: u8 = 4;
const RT_GP8HI: u8 = 5;
const RT_GP16: u8 = 6;
const RT_GP32: u8 = 7;
const RT_GP64: u8 = 8;
const RT_VEC128: u8 = 13;
const RT_VEC256: u8 = 14;
const RT_VEC512: u8 = 15;
const RT_MASK: u8 = 17;
const RT_MM: u8 = 18; // RegType::Extra == X86Mm
const RT_SREG: u8 = 19;
const RT_CREG: u8 = 20;
const RT_DREG: u8 = 21;
const RT_ST: u8 = 22;
const RT_TMM: u8 = 24;

// Operand kind tags in the record.
const OK_REG: u8 = 1;
const OK_MEM: u8 = 2;
const OK_IMM: u8 = 3;
const OK_LABEL: u8 = 4;

// Label layout tags in the record.
const LL_SELF: u8 = 0; // label bound at the instruction's own offset
const LL_FAR_BACK: u8 = 1; // label bound at block start, 200 pad bytes before the instruction
const LL_FAR_FWD: u8 = 2; // label bound after instruction + 200 pad bytes
const LABEL_PAD: usize = 200;

const MAGIC: &[u8; 8] = b"AKDFCOR1";

// ============================================================================
// Options (prefixes / EVEX extras) applied before emit.
// ============================================================================
#[derive(Clone, Copy, Default, PartialEq, Eq, PartialOrd, Ord)]
struct Opts {
    lock: bool,
    rep: bool,
    repnz: bool,
    seg: u8,       // 0 = none, 1..=6 = es,cs,ss,ds,fs,gs
    er: u8,        // 0 = none, 1 = sae, 2 = rn, 3 = rd, 4 = ru, 5 = rz
    k: Option<u8>, // EVEX mask register id
}

// ============================================================================
// Stats
// ============================================================================
#[derive(Default)]
struct Stats {
    attempts: u64,
    from_mnem_ok: u64,
    emit_ok: u64,
    panics: u64,
    records: u64,
    bytes: u64,
    verify_dropped: u64,
    sym_forms_skipped: u64,
    mixed_label_skipped: u64,
    mnems_covered: HashSet<&'static str>,
    drop_reasons: BTreeMap<(String, String), u64>,
}

// ============================================================================
// Record: one corpus entry.
// ============================================================================
struct OpRec {
    kind: u8,
    // reg
    rt: u8,
    id: u8,
    // mem
    base_rt: u8,
    base_id: u8,
    index_rt: u8,
    index_id: u8,
    scale: u8,
    size: u8,
    addr_type: u8,
    broadcast: u8,
    disp: i64,
}

impl OpRec {
    fn none() -> Self {
        Self {
            kind: 0,
            rt: 0,
            id: 0,
            base_rt: 0,
            base_id: 0,
            index_rt: 0,
            index_id: 0,
            scale: 0,
            size: 0,
            addr_type: 0,
            broadcast: 0,
            disp: 0,
        }
    }

    /// Read back an operand exactly as the encoder consumed it.
    fn from_operand(op: &Operand) -> Self {
        let mut r = Self::none();
        if op.is_reg() {
            let reg = op.as_::<Reg>();
            r.kind = OK_REG;
            r.rt = reg.typ() as u32 as u8;
            r.id = reg.id() as u8;
        } else if op.is_mem() {
            let m = op.as_::<Mem>();
            r.kind = OK_MEM;
            r.base_rt = m.base_type() as u32 as u8;
            r.base_id = m.base_id() as u8;
            r.index_rt = m.index_type() as u32 as u8;
            r.index_id = m.index_id() as u8;
            r.scale = m.shift() as u8;
            r.size = m.size() as u8;
            r.addr_type = m.addr_type() as u32 as u8;
            r.broadcast = m.get_broadcast() as u32 as u8;
            r.disp = m.offset();
        } else if op.is_imm() {
            r.kind = OK_IMM;
            r.disp = op.as_::<Imm>().value();
        } else if op.is_label() {
            r.kind = OK_LABEL;
        }
        r
    }

    fn write(&self, w: &mut Vec<u8>) {
        w.push(self.kind);
        match self.kind {
            OK_REG => {
                w.push(self.rt);
                w.push(self.id);
            }
            OK_MEM => {
                w.push(self.base_rt);
                w.push(self.base_id);
                w.push(self.index_rt);
                w.push(self.index_id);
                w.push(self.scale);
                w.push(self.size);
                w.push(self.addr_type);
                w.push(self.broadcast);
                w.extend_from_slice(&self.disp.to_le_bytes());
            }
            OK_IMM => {
                w.extend_from_slice(&self.disp.to_le_bytes());
            }
            _ => {}
        }
    }
}

struct Record {
    mnem: String,
    opcode: i64,
    opts: Opts,
    ops: Vec<OpRec>,
    label_layout: u8,       // 0xFF = no label
    label_bind_offset: i32, // -1 = no label
    instr_offset: u32,
    instr_len: u32,
    block: Vec<u8>,
}

impl Record {
    fn write(&self, w: &mut dyn Write) -> std::io::Result<()> {
        let mut p = Vec::with_capacity(64 + self.block.len());
        p.extend_from_slice(&(self.mnem.len() as u16).to_le_bytes());
        p.extend_from_slice(self.mnem.as_bytes());
        p.extend_from_slice(&self.opcode.to_le_bytes());
        p.push(self.ops.len() as u8);
        p.push(
            (self.opts.lock as u8) | ((self.opts.rep as u8) << 1) | ((self.opts.repnz as u8) << 2),
        );
        p.push(self.opts.seg | (self.opts.er << 3) | ((self.opts.k.is_some() as u8) << 6));
        p.push(self.opts.k.unwrap_or(0));
        p.push(self.label_layout);
        p.extend_from_slice(&self.label_bind_offset.to_le_bytes());
        p.extend_from_slice(&self.instr_offset.to_le_bytes());
        p.extend_from_slice(&self.instr_len.to_le_bytes());
        for op in &self.ops {
            op.write(&mut p);
        }
        p.extend_from_slice(&(self.block.len() as u32).to_le_bytes());
        p.extend_from_slice(&self.block);
        w.write_all(&(p.len() as u32).to_le_bytes())?;
        w.write_all(&p)
    }
}

// ============================================================================
// Emission
// ============================================================================
fn apply_opts(asm: &mut Assembler, opts: &Opts) {
    if opts.lock {
        asm.lock();
    }
    if opts.rep {
        asm.rep();
    }
    if opts.repnz {
        asm.repnz();
    }
    if opts.seg != 0 {
        asm.seg(asmkit::x86::operands::regs::sreg(opts.seg as u32));
    }
    match opts.er {
        1 => {
            asm.sae();
        }
        2 => {
            asm.rn_sae();
        }
        3 => {
            asm.rd_sae();
        }
        4 => {
            asm.ru_sae();
        }
        5 => {
            asm.rz_sae();
        }
        _ => {}
    }
    if let Some(k) = opts.k {
        asm.k(asmkit::x86::operands::regs::k(k as u32));
    }
}

struct EmitOut {
    block: Vec<u8>,
    instr_offset: u32,
    instr_len: u32,
    label_bind_offset: i32,
}

/// Emit `instr` with `opts` into a fresh buffer. `label_layout` applies when
/// one of the operands is a label (the operand value is created here).
/// Returns None when the encoder reports an error or panics.
fn emit_record(
    instr_ops: &[Operand],
    opcode: i64,
    opts: &Opts,
    label_layout: u8,
    panics: &mut u64,
) -> Option<EmitOut> {
    let mut buf = CodeBuffer::new();
    let mut asm = Assembler::new(&mut buf);

    let mut ops: Vec<Operand> = instr_ops.to_vec();
    let mut label = None;
    if label_layout != 0xFF {
        let l = asm.get_label();
        label = Some(l);
        for o in ops.iter_mut() {
            if o.is_label() {
                *o = *l.as_operand();
            }
        }
        if label_layout != LL_FAR_FWD {
            asm.bind_label(l);
            if label_layout == LL_FAR_BACK {
                for _ in 0..LABEL_PAD {
                    asm.buffer.put1(0x90);
                }
            }
        }
    }

    let instr_offset = asm.buffer.cur_offset();
    apply_opts(&mut asm, opts);

    let instr = Instruction {
        opcode,
        op0: ops.first().copied().unwrap_or_else(Operand::new),
        op1: ops.get(1).copied().unwrap_or_else(Operand::new),
        op2: ops.get(2).copied().unwrap_or_else(Operand::new),
        op3: ops.get(3).copied().unwrap_or_else(Operand::new),
    };

    let ok = std::panic::catch_unwind(AssertUnwindSafe(|| {
        instr.emit(&mut asm);
    }))
    .is_ok();
    if !ok {
        *panics += 1;
        return None;
    }
    if asm.last_error().is_some() {
        return None;
    }
    let instr_len = asm.buffer.cur_offset() - instr_offset;
    if instr_len == 0 {
        return None;
    }

    let mut label_bind_offset = -1i32;
    if let Some(l) = label {
        if label_layout == LL_FAR_FWD {
            for _ in 0..LABEL_PAD {
                asm.buffer.put1(0x90);
            }
            asm.bind_label(l);
        }
        // Apply pending fixups (all labels are bound at this point, so no
        // veneers can be emitted).
        asm.buffer.emit_island(0);
        if asm.last_error().is_some() {
            return None;
        }
        label_bind_offset = asm.label_offset(l) as i32;
    }

    Some(EmitOut {
        block: asm.buffer.data().to_vec(),
        instr_offset,
        instr_len,
        label_bind_offset,
    })
}

