    fn reg_of(rt: u8, id: u8) -> Option<Register> {
        let i = id as usize;
        Some(match rt {
            RT_GP8LO => *GP8LO.get(i)?,
            RT_GP8HI => *GP8HI.get(i)?,
            RT_GP16 => *GP16.get(i)?,
            RT_GP32 => *GP32.get(i)?,
            RT_GP64 => *GP64.get(i)?,
            RT_VEC128 => *XMM.get(i)?,
            RT_VEC256 => *YMM.get(i)?,
            RT_VEC512 => *ZMM.get(i)?,
            RT_MASK => *KREG.get(i)?,
            RT_MM => *MMREG.get(i)?,
            RT_ST => *STREG.get(i)?,
            RT_SREG => *SREG.get(i)?,
            RT_CREG => *CREG.get(i)?,
            RT_DREG => *DREG.get(i)?,
            RT_TMM => *TMM.get(i)?,
            RT_PC => Register::RIP,
            _ => return None,
        })
    }

